import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello 🌱 I'm glad you reached out. Are you feeling stressed right now?"
    }
  ]);

  const [input, setInput] = useState("");

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();

    const lastBotMessage =
      previousMessages
        .slice()
        .reverse()
        .find((msg) => msg.sender === "bot")?.text.toLowerCase() || "";

    /* ------------------- STEP 1: Acknowledge STRESS ------------------- */
    if (
      text.includes("stress") ||
      text.includes("stressed") ||
      text.includes("pressure")
    ) {
      return "I hear you 💙 Stress can be really heavy. Is it more emotional stress, physical stress, or a mix of both?";
    }

    /* ------------------- STEP 2: TYPE OF STRESS ------------------- */
    if (
      lastBotMessage.includes("emotional stress") ||
      lastBotMessage.includes("physical stress")
    ) {
      if (text.includes("both") || text.includes("mix")) {
        return "That sounds exhausting. When stress affects both mind and body, it can feel overwhelming. What is the main source of this stress right now — studies, work, family, or something else?";
      }

      if (text.includes("emotional")) {
        return "Emotional stress can drain you deeply. What’s been weighing on your mind lately?";
      }

      if (text.includes("physical")) {
        return "Physical stress affects your energy a lot. Is it due to lack of sleep, overwork, or constant tiredness?";
      }
    }

    /* ------------------- STEP 3: SOURCE OF STRESS ------------------- */
    if (
      text.includes("study") ||
      text.includes("exam") ||
      text.includes("college")
    ) {
      return "Studies can be very demanding. What part stresses you the most — workload, fear of exams, or pressure to perform well?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work stress can be draining. Is it the workload, deadlines, or pressure from others that affects you most?";
    }

    if (text.includes("family")) {
      return "Family pressure can be emotionally heavy. What about your family situation is causing stress for you?";
    }

    if (text.includes("future") || text.includes("career")) {
      return "Uncertainty about the future can feel scary. What worries you most when you think about your future?";
    }

    /* ------------------- STEP 4: SPECIFIC ISSUE ------------------- */
    if (
      text.includes("marks") ||
      text.includes("performance") ||
      text.includes("fail")
    ) {
      return "Fear of performance can create constant pressure. What do you feel would happen if things don’t go as expected?";
    }

    if (text.includes("too much") || text.includes("overwhelmed")) {
      return "Feeling overwhelmed is a sign you’ve been carrying a lot. How has this stress been affecting you daily — your sleep, focus, or mood?";
    }

    /* ------------------- STEP 5: IMPACT ------------------- */
    if (
      text.includes("sleep") ||
      text.includes("focus") ||
      text.includes("tired") ||
      text.includes("headache")
    ) {
      return "That sounds really tough 😔 When stress starts affecting your body and routine, it’s important to slow down. Would you like a small grounding exercise, or do you want to talk more about what you’re feeling?";
    }

    /* ------------------- FALLBACK (KEEP CONVERSATION GOING) ------------------- */
    if (text.length > 5) {
      return "Thank you for sharing 🌼 I’m listening. Can you tell me a bit more about how this stress feels inside you?";
    }

    return "Take your time 💙 You can share whatever feels comfortable.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input, messages)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk about stress</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share what's stressing you..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
